import{_ as c,o as s,c as a,a2 as e}from"./chunks/framework.N6Nd-M9-.js";const m=JSON.parse('{"title":"观察日","description":"","frontmatter":{},"headers":[],"relativePath":"notes/企业文化/组长手册/03-观察日.md","filePath":"notes/企业文化/组长手册/03-观察日.md"}'),l={name:"notes/企业文化/组长手册/03-观察日.md"};function r(i,t,d,n,o,p){return s(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="观察日" tabindex="-1">观察日 <a class="header-anchor" href="#观察日" aria-label="Permalink to &quot;观察日&quot;">​</a></h1><blockquote><p>带观察日是你个人发展的需要，同时也是成就他人的开始。每个观察日都可能成为你的左右手，也都有可能是你未来的经理。对待观察日不能不重视但也不能太在乎：你是机会的给予者，不必处心积虑去取悦对方，也不要用自己个人的喜好来决定其去留。</p></blockquote><hr><h2 id="一、带观察日的流程" tabindex="-1">一、带观察日的流程 <a class="header-anchor" href="#一、带观察日的流程" aria-label="Permalink to &quot;一、带观察日的流程&quot;">​</a></h2><div class="tc-grid tc-grid-auto" style="gap:15px;"><div class="tc-card tc-card-blue"><p class="tc-title tc-blue">📋 提前准备</p><div class="tc-flex tc-flex-col" style="gap:8px;"><span class="tc-item tc-item-blue tc-body">✓ 精神面貌、衣着、发型</span><span class="tc-item tc-item-blue tc-body">✓ 与拍档打好预防针</span><span class="tc-item tc-item-blue tc-body">✓ 组长必须保持和善和不吝指导的态度</span><span class="tc-item tc-item-red tc-body">✗ 不要带观察日去吃早餐——良好习惯的开端</span></div></div><div class="tc-card tc-card-green"><p class="tc-title tc-green">🌅 早上</p><div class="tc-flex tc-flex-col" style="gap:8px;"><span class="tc-item tc-item-green tc-body"><strong>见面打招呼</strong>：主动握手要有力度；出发时要做出请的姿势；微笑，眼神接触和热忱</span><span class="tc-item tc-item-green tc-body"><strong>公司到楼下</strong>：认识并建立关系，说明今天的流程安排及目的（记住对方姓名；在楼下沟通要正式、专业）</span><span class="tc-item tc-item-green tc-body"><strong>楼下到目的地</strong>：进一步了解个人情况，拉近关系并简单推广企业</span></div></div><div class="tc-card tc-card-orange"><p class="tc-title tc-orange">📍 到达目的地</p><div class="tc-flex tc-flex-col" style="gap:8px;"><span class="tc-item tc-item-orange tc-body">说明今天的工作流程（让观察日觉得轻松简单）</span><span class="tc-item tc-item-orange tc-body">给观察日做简单的五步推广</span><span class="tc-item tc-item-orange tc-body">说明市场行销系统及我们为什么采用这种销售方式（我们的营销策略——直接有效、简单易学易做）</span><span class="tc-item tc-item-orange tc-body">简单的介绍平均法（证明可以找到成交的客户，为可能发生的负面做准备）</span></div></div><div class="tc-card tc-card-red"><p class="tc-title tc-red">💼 作业中</p><div class="tc-flex tc-flex-col" style="gap:8px;"><span class="tc-item tc-item-red tc-body"><strong>上午</strong>：示范性地教导五步。忽略市场中的问题和困难，传授重心是学习和积累经验的概念</span><span class="tc-item tc-item-red tc-body"><strong>中午</strong>：简单推广公司前景及这次招聘的目的；介绍公司的生意系统；沟通上午的作业过程</span><span class="tc-item tc-item-red tc-body"><strong>下午</strong>：增加互动，继续教导五步、八点、平均法</span><span class="tc-item tc-item-red tc-body"><strong>作业结束</strong>：如决定带他回公司复试，先对他一天的表现给予肯定，同时给予失落感</span></div><div style="margin-top:10px;"><p class="tc-sm tc-red">⚠️ 注：在作业过程中，适当休息一两分钟，补充水分，并随时与他检查及探讨平均法表。</p></div></div></div><hr><h2 id="二、车上沟通要点" tabindex="-1">二、车上沟通要点 <a class="header-anchor" href="#二、车上沟通要点" aria-label="Permalink to &quot;二、车上沟通要点&quot;">​</a></h2><div class="tc-container tc-container-blue"><p class="tc-title tc-blue">🚗 楼下到目的地</p><div class="tc-flex tc-flex-col" style="gap:10px;"><span class="tc-item tc-item-blue tc-body"><strong>a)</strong> 了解对方的个性、背景资料、兴趣、关注点</span><span class="tc-item tc-item-blue tc-body"><strong>b)</strong> 了解他上一份工作、离职原因</span><span class="tc-item tc-item-blue tc-body"><strong>c)</strong> 说说你的工作——成长的潜力、财务的利润、工作的乐趣、发展的机会……</span></div><p class="tc-sm tc-red">⚠️ 注：在车上千万不能冷落观察日，更不能睡觉或只顾与其它组长聊天；同时避免观察日与拍档的观察日交流。</p></div><div class="tc-container tc-container-green"><p class="tc-title tc-green">🔄 回程车上</p><div class="tc-flex tc-flex-col" style="gap:10px;"><span class="tc-item tc-item-green tc-body">✓ 不能冷落新人，可与其沟通工作感受及心得</span><span class="tc-item tc-item-green tc-body">✓ 适当讲述你自己进公司时的感觉、对公司的看法、为什么留在公司</span><span class="tc-item tc-item-green tc-body">✓ 推广公司与其经历差不多的人</span></div></div><hr><h2 id="三、回到公司" tabindex="-1">三、回到公司 <a class="header-anchor" href="#三、回到公司" aria-label="Permalink to &quot;三、回到公司&quot;">​</a></h2><div class="tc-grid tc-grid-auto" style="gap:12px;"><div class="tc-card tc-card-blue"><p class="tc-subtitle tc-blue">📝 填写复试表</p><p class="tc-sm tc-body">安排并全程陪同他填写复试表（不要冷落他，不能走开，陪在旁边，不要让他与其它观察日交流，严肃认真对待并给予失落感）</p></div><div class="tc-card tc-card-green"><p class="tc-subtitle tc-green">📤 提交汇报</p><p class="tc-sm tc-body">填好后把复试表交给经理，并如实汇报你的情况及观察日的情况</p></div><div class="tc-card tc-card-orange"><p class="tc-subtitle tc-orange">🚪 进办公室</p><p class="tc-sm tc-body">带观察日进办公室前先敲门，给予失落感的同时要给予鼓励（出来后不要跑太远，以便经理叫你）</p></div><div class="tc-card tc-card-red"><p class="tc-subtitle tc-red">🎉 通过复试</p><p class="tc-sm tc-body">如观察日通过经理的复试，要真诚的恭喜他。并介绍几位组长、准副理或与其情况类似的优秀同事给他认识，但不能超过10分钟，将他送走前一定要确认对方的电话</p></div></div><div class="tc-alert tc-alert-red"><p class="tc-sm tc-body"><strong>⚠️ 注意：</strong>送观察日时注意不能与其它观察日一起送，防止交流负面；下班后打电话问候和关心。</p></div><hr><h2 id="四、带观察日的原则" tabindex="-1">四、带观察日的原则 <a class="header-anchor" href="#四、带观察日的原则" aria-label="Permalink to &quot;四、带观察日的原则&quot;">​</a></h2><div class="tc-grid tc-grid-sm" style="gap:12px;"><div class="tc-card tc-card-blue tc-center"><p class="tc-icon">🎯</p><p class="tc-subtitle tc-blue">定位</p><p class="tc-sm tc-body">你是给机会的人<br>让他感觉你在对他进行全程的考核</p></div><div class="tc-card tc-card-green tc-center"><p class="tc-icon">👔</p><p class="tc-subtitle tc-green">专业形象</p><p class="tc-sm tc-body">专业的形象<br>形象差是不能够带观察日的<br>因为这样不利于留存</p></div><div class="tc-card tc-card-orange tc-center"><p class="tc-icon">⭐</p><p class="tc-subtitle tc-orange">榜样</p><p class="tc-sm tc-body">榜样要做好<br>言谈举止要符合组长的身份<br>销售榜样要做好，表现出你的拼劲和一定要的决心</p></div><div class="tc-card tc-card-red tc-center"><p class="tc-icon">🤝</p><p class="tc-subtitle tc-red">互动</p><p class="tc-sm tc-body">交朋友、建关系<br>开心作业（让观察日觉得轻松、简单、乐趣）<br>千万不要冷落观察日、只顾自己的事，让观察日参与进来</p></div></div><hr><h2 id="五、留存关键" tabindex="-1">五、留存关键 <a class="header-anchor" href="#五、留存关键" aria-label="Permalink to &quot;五、留存关键&quot;">​</a></h2><div class="tc-gradient tc-gradient-blue-green"><blockquote class="tc-quote tc-quote-blue tc-body"> 让观察日学到东西；看到系统的成功、赚钱的可能、工作的乐趣；看到、听到、感觉到发展（榜样、拼劲、创业精神），这些才是留存的关键。 </blockquote><p class="tc-sm tc-muted">💡 注：教育队员从被录用起就由你负责。每日都需要真诚地表示你对其成长的关注，直到彼此建立良好的关系且他具备正确的态度、独立运作系统的能力为止。</p></div>',19)])])}const g=c(l,[["render",r]]);export{m as __pageData,g as default};
